        lua_pushnumber(L, 1); 
        lua_setfield(L, -2, "field1");

        lua_pushnumber(L, 2);
        lua_setfield(L, -2, "field2");

        lua_pushnumber(L, 3);
        lua_setfield(L, -2, "field3");

    lua_settable(L, -3);

    lua_pushnumber(L, 2);
        lua_createtable(L, 0, 3);

        lua_pushnumber(L, 10);
        lua_setfield(L, -2, "field1");

        lua_pushnumber(L, 20);
        lua_setfield(L, -2, "field2");

